const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','sub_agent','mga_principal','admin','supervisor'];
if (allowed.indexOf(row.user_role) === -1) return { json: { _unauthorized: true, status: 403 } };
const b = $('Extract').first().json.body;
const incomeReplacement = parseFloat(b.income_replacement_cents) || 0;
const mortgageDebt = parseFloat(b.mortgage_debt_cents) || 0;
const dependentSupport = parseFloat(b.dependent_support_cents) || 0;
const finalExpenses = parseFloat(b.final_expenses_cents) || 0;
const education = parseFloat(b.education_cents) || 0;
const existingCoverage = parseFloat(b.existing_coverage_cents) || 0;
const gross = incomeReplacement + mortgageDebt + dependentSupport + finalExpenses + education;
const gap = Math.max(0, gross - existingCoverage);
return { json: { ok: true, calculator: 'total_needs', vertical_id: 'insurance', coverage_amount_cents: gap, breakdown: { income_replacement_cents: incomeReplacement, mortgage_debt_cents: mortgageDebt, dependent_support_cents: dependentSupport, final_expenses_cents: finalExpenses, education_cents: education, gross_need_cents: gross, existing_coverage_cents: existingCoverage }, disclaimer: 'This is an educational estimate only. Final recommendation must be reviewed and approved by a licensed advisor.' } };
